 * Thrown by date-time arithmetic operations if the result can not be computed or represented.
 *
 * This exception can be thrown in several scenarios:
 * - When arithmetic operations on [Instant] or [LocalDateTime] produce results that exceed the
 *   representable range (e.g., adding many years to a date).
 * - When converting an [Instant] to [LocalDateTime] and the result is outside the valid range.
 * - When performing period calculations between dates or instants that are too far apart.
 *
 * Example situations where this exception may be thrown:
 * ```
 * // Adding a large period to an instant
 * val instant = Clock.System.now()
 * instant.plus(DateTimePeriod(years = 1000000), TimeZone.UTC) // May throw
 *
 * // Converting a distant instant to LocalDateTime
 * Instant.DISTANT_FUTURE.toLocalDateTime(TimeZone.UTC) // OK
 * (Instant.DISTANT_FUTURE + 1.nanoseconds).toLocalDateTime(TimeZone.UTC) // May throw
 * ```
 *
 * @see Instant.plus
 * @see Instant.toLocalDateTime
 * @see LocalDate.plus
 */
public class DateTimeArithmeticException: RuntimeException {
    public constructor(): super()
    public constructor(message: String): super(message)
    public constructor(cause: Throwable): super(cause)
    public constructor(message: String, cause: Throwable): super(message, cause)
}

/**
 * Thrown when attempting to construct a [TimeZone] with an invalid ID.
 *
 * This exception is thrown by [TimeZone.of] when the provided time zone identifier is not recognized
 * or has an invalid format.
 *
 * Valid time zone identifiers include:
 * - IANA time zone database identifiers: `"Europe/Berlin"`, `"America/New_York"`, `"Asia/Tokyo"`
 * - Fixed offset identifiers: `"UTC"`, `"UTC+5"`, `"GMT-8"`, `"+05:30"`
 * - The special identifier `"Z"` for UTC
 *
 * Example:
 * ```
 * TimeZone.of("Europe/Berlin") // OK
 * TimeZone.of("Invalid/Zone") // Throws IllegalTimeZoneException
 * ```
 *
 * The set of available time zone identifiers can be queried via [TimeZone.availableZoneIds].
 *
 * @see TimeZone.of
 * @see TimeZone.availableZoneIds
 */
public class IllegalTimeZoneException: IllegalArgumentException {
    public constructor(): super()
    public constructor(message: String): super(message)
    public constructor(cause: Throwable): super(cause)
    public constructor(message: String, cause: Throwable): super(message, cause)
}"}

